class Solution:
    def smallestEquivalentString(self, s1: str, s2: str, baseStr: str) -> str:
        equivalence = {}
        for i in range(len(s1)):
            equivalence[s1[i]] = s2[i]
        result = []
        for char in baseStr:
            result.append(equivalence.get(char, char))
        return ''.join(result)
